import{_ as e,o as a,c as n,ae as o}from"./chunks/framework.BdQd5MxT.js";const p=JSON.parse('{"title":"Anthropic: How We Built Our Multi-Agent Research System","description":"","frontmatter":{},"headers":[],"relativePath":"bestpractice/anthropic-multi-agent-research.md","filePath":"bestpractice/anthropic-multi-agent-research.md"}'),r={name:"bestpractice/anthropic-multi-agent-research.md"};function l(i,t,s,h,c,d){return a(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="anthropic-how-we-built-our-multi-agent-research-system" tabindex="-1">Anthropic: How We Built Our Multi-Agent Research System <a class="header-anchor" href="#anthropic-how-we-built-our-multi-agent-research-system" aria-label="Permalink to &quot;Anthropic: How We Built Our Multi-Agent Research System&quot;">​</a></h1><blockquote><p>来源: <a href="https://anthropic.com/engineering/multi-agent-research-system" target="_blank" rel="noreferrer">anthropic.com/engineering/multi-agent-research-system</a> 日期: 2025-06-13 分析: WLB</p></blockquote><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>Anthropic 用 <strong>Orchestrator-Worker</strong> 模式构建了多 Agent 研究系统，比单 Agent 强 90.2%，但 token 消耗 15 倍。</p><hr><h2 id="核心架构" tabindex="-1">核心架构 <a class="header-anchor" href="#核心架构" aria-label="Permalink to &quot;核心架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户查询</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Lead Agent（规划 + 协调）</span></span>
<span class="line"><span>    ↓ ↓ ↓</span></span>
<span class="line"><span>Subagent₁  Subagent₂  Subagent₃ （并行搜索）</span></span>
<span class="line"><span>    ↓ ↓ ↓</span></span>
<span class="line"><span>汇总 → 最终回答</span></span></code></pre></div><p><strong>关键设计：</strong></p><ul><li>每个 Subagent 有<strong>独立 context window</strong> — 避免 path dependency</li><li>Lead Agent 使用 <strong>Memory</strong> 持久化计划 — 防止 context 溢出丢失</li><li>Subagent 是&quot;智能过滤器&quot; — 迭代搜索后返回关键信息</li><li>传统 RAG = 静态检索；他们的架构 = <strong>多步动态搜索</strong></li></ul><hr><h2 id="关键数据" tabindex="-1">关键数据 <a class="header-anchor" href="#关键数据" aria-label="Permalink to &quot;关键数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th><th>含义</th></tr></thead><tbody><tr><td>Multi-agent vs 单 Agent</td><td><strong>+90.2%</strong></td><td>内部 research eval 性能提升</td></tr><tr><td>Token 消耗倍率</td><td><strong>15x</strong> (vs chat)</td><td>Multi-agent 很贵</td></tr><tr><td>性能差异解释</td><td><strong>95% 由 3 因素</strong></td><td>Token 用量 (80%) + 工具调用 + 模型选择</td></tr></tbody></table><h3 id="token-用量是最关键因素" tabindex="-1">Token 用量是最关键因素 <a class="header-anchor" href="#token-用量是最关键因素" aria-label="Permalink to &quot;Token 用量是最关键因素&quot;">​</a></h3><p>Anthropic 发现 <strong>token 用量本身就解释了 80% 的性能差异</strong>。这意味着：</p><blockquote><p>&quot;砸够多 token 就能解决问题&quot; — 但这不经济，需要架构设计来提高 token 效率。</p></blockquote><p>Multi-agent 的核心价值：通过<strong>并行 context window</strong> 突破单 agent 容量限制。</p><hr><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><h3 id="✅-适合-multi-agent" tabindex="-1">✅ 适合 Multi-Agent <a class="header-anchor" href="#✅-适合-multi-agent" aria-label="Permalink to &quot;✅ 适合 Multi-Agent&quot;">​</a></h3><ul><li>Breadth-first 查询（多方向并行搜索）</li><li>超出单 context 窗口的大任务</li><li>高价值任务（值得 15x token 成本）</li><li>需要接口众多复杂工具</li></ul><h3 id="❌-不适合" tabindex="-1">❌ 不适合 <a class="header-anchor" href="#❌-不适合" aria-label="Permalink to &quot;❌ 不适合&quot;">​</a></h3><ul><li>Coding 任务（并行化少，依赖多）</li><li>所有 agent 需要共享同一 context</li><li>低价值任务（token 成本不划算）</li><li>需要 agent 间实时协调的任务</li></ul><hr><h2 id="核心洞察" tabindex="-1">核心洞察 <a class="header-anchor" href="#核心洞察" aria-label="Permalink to &quot;核心洞察&quot;">​</a></h2><h3 id="_1-并行化是核心价值" tabindex="-1">1. 并行化是核心价值 <a class="header-anchor" href="#_1-并行化是核心价值" aria-label="Permalink to &quot;1. 并行化是核心价值&quot;">​</a></h3><blockquote><p>&quot;Multi-agent systems excel at valuable tasks that involve heavy parallelization&quot;</p></blockquote><p>单 agent 做 S&amp;P 500 IT 公司董事会搜索 → 失败（太慢，顺序搜索） Multi-agent → 成功（分解为子任务并行搜索）</p><h3 id="_2-context-分离-减少-path-dependency" tabindex="-1">2. Context 分离 = 减少 Path Dependency <a class="header-anchor" href="#_2-context-分离-减少-path-dependency" aria-label="Permalink to &quot;2. Context 分离 = 减少 Path Dependency&quot;">​</a></h3><p>每个 agent 独立探索，避免&quot;一个走偏带偏全局&quot;。</p><h3 id="_3-扩展-intelligence-的方式" tabindex="-1">3. 扩展 Intelligence 的方式 <a class="header-anchor" href="#_3-扩展-intelligence-的方式" aria-label="Permalink to &quot;3. 扩展 Intelligence 的方式&quot;">​</a></h3><blockquote><p>&quot;Even generally-intelligent agents face limits when operating as individuals; groups of agents can accomplish far more.&quot;</p></blockquote><p>就像人类：单个人智力没怎么变，但社会集体能力指数级增长。</p><h3 id="_4-token-经济学是硬约束" tabindex="-1">4. Token 经济学是硬约束 <a class="header-anchor" href="#_4-token-经济学是硬约束" aria-label="Permalink to &quot;4. Token 经济学是硬约束&quot;">​</a></h3><ul><li>单 Agent chat: 1x tokens</li><li>单 Agent (agentic): 4x tokens</li><li>Multi-agent: 15x tokens</li></ul><p><strong>只有高价值任务才值得。</strong></p><hr><h2 id="对我们的借鉴" tabindex="-1">对我们的借鉴 <a class="header-anchor" href="#对我们的借鉴" aria-label="Permalink to &quot;对我们的借鉴&quot;">​</a></h2><h3 id="wlb-gsd-架构启示" tabindex="-1">WLB + GSD 架构启示 <a class="header-anchor" href="#wlb-gsd-架构启示" aria-label="Permalink to &quot;WLB + GSD 架构启示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Anthropic 做法</th><th>我们的现状</th><th>借鉴</th></tr></thead><tbody><tr><td>Lead Agent + Subagent 并行</td><td>WLB(决策) + GSD(执行)，手动协调</td><td>考虑自动化派生 subagent</td></tr><tr><td>Memory 持久化计划</td><td>无（靠 Slack 消息传递）</td><td>长任务需要中间状态持久化</td></tr><tr><td>独立 context window</td><td>各自独立 session ✅</td><td>已有，保持</td></tr><tr><td>Token 预算意识</td><td>无</td><td>需要评估任务价值 vs token 成本</td></tr></tbody></table><h3 id="可行动项" tabindex="-1">可行动项 <a class="header-anchor" href="#可行动项" aria-label="Permalink to &quot;可行动项&quot;">​</a></h3><ol><li><strong>评估任务是否适合 multi-agent</strong> — 不是所有任务都值得</li><li><strong>引入 Memory 机制</strong> — 长任务的中间状态持久化到文件</li><li><strong>监控 token 用量</strong> — 知道每个任务花了多少 token</li><li><strong>保持 Context 分离</strong> — 已经做好了，继续保持</li></ol><hr><h2 id="原文引用" tabindex="-1">原文引用 <a class="header-anchor" href="#原文引用" aria-label="Permalink to &quot;原文引用&quot;">​</a></h2><blockquote><p>&quot;Once intelligence reaches a threshold, multi-agent systems become a vital way to scale performance.&quot;</p></blockquote><blockquote><p>&quot;Multi-agent systems work mainly because they help spend enough tokens to solve the problem.&quot;</p></blockquote><blockquote><p>&quot;For economic viability, multi-agent systems require tasks where the value of the task is high enough to pay for the increased performance.&quot;</p></blockquote><hr><p><em>下一篇: <a href="/LIP/bestpractice/anthropic-context-engineering.html">Context Engineering 深度分析 →</a></em></p>`,49)])])}const g=e(r,[["render",l]]);export{p as __pageData,g as default};
